mapper.insert:
insert into tbl_gallery (
    member_id, title, description, cover_image, allow_comment, show_similar, status
) values (
    #{memberId}, #{title}, #{description}, #{coverImage}, coalesce(#{allowComment}, true), coalesce(#{showSimilar}, true), 'EXHIBITING'
)

insert into tbl_gallery_work (
    gallery_id, work_id, sort_order
) values (
    #{galleryId}, #{workId}, 0
)

insert into tbl_gallery_tag (
    gallery_id, tag_id
) values (
    #{galleryId}, #{tagId}
)

insert into tbl_comment (
    member_id, target_type, target_id, parent_id, content, is_pinned, like_count
) values (
    #{memberId}, #{targetType}, #{targetId}, #{parentId}, #{content}, coalesce(#{isPinned}, false), coalesce(#{likeCount}, 0)
)

mapper.select:
select g.id, g.member_id, g.title, g.description, g.cover_image, m.nickname as member_nickname, g.work_count, g.like_count, g.view_count, false as is_liked, g.created_datetime from tbl_gallery g left join tbl_member m on g.member_id = m.id where g.deleted_datetime is null and g.status != 'DELETED'
and (g.title ilike '%' || #{keyword} || '%' or g.description ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%')
and g.member_id = #{memberId}
and g.status = #{status}
order by g.created_datetime desc, g.id desc limit #{size} offset (#{page} - 1) * #{size}

select count(*) from tbl_gallery g left join tbl_member m on g.member_id = m.id where g.deleted_datetime is null and g.status != 'DELETED'
and (g.title ilike '%' || #{keyword} || '%' or g.description ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%')
and g.member_id = #{memberId}
and g.status = #{status}

select exists (
    select 1
    from tbl_gallery_like
    where member_id = #{memberId}
      and gallery_id = #{galleryId}
)

mapper.insert:
insert into tbl_gallery_like (
    member_id, gallery_id
) values (
    #{memberId}, #{galleryId}
)

mapper.delete:
delete from tbl_gallery_like
where member_id = #{memberId}
  and gallery_id = #{galleryId}
